def from_dict(d: dict[str, Any]) -> dict[str, Any]:
        """Correct fields in Dictionary for JSON deserialization."""
        if 'mutant' in d:
            d['mutant'] = Mutant(**Mutant.from_dict(d['mutant']))
        if 'result' in d:
            d['result'] = MutantTrialResult(**d['result'])
        return d

def from_dict(d: dict[str, Any]) -> dict[str, Any]:
        """Correct fields in Dictionary for JSON deserialization."""
        if 'mutant_trials' in d:
            d['mutant_trials'] = [MutantTrial(**MutantTrial.from_dict(trial)) for trial in d['mutant_trials']]
        if 'summary' in d and d['summary'] is not None:
            d['summary'] = TestingSummary(**TestingSummary.from_dict(d['summary']))
        return d

def get_location(node: ast.AST) -> tuple[int, int, int, int]:
        """Get location lines and columns that encompasses node and all child nodes."""
        lineno = node.lineno
        col_offset = node.col_offset
        end_lineno = node.end_lineno or node.lineno
        end_col_offset = node.end_col_offset or node.col_offset
        for n in ast.walk(node):
            if not hasattr(n, 'lineno'):
                continue
            if n.lineno < lineno:
                lineno = n.lineno
                if n.col_offset < col_offset:
                    col_offset = n.col_offset
            elif n.lineno == lineno and n.col_offset < col_offset:
                col_offset = n.col_offset
            if not hasattr(n, 'end_lineno') or not n.end_lineno:
                continue
            if n.end_lineno > end_lineno:
                end_lineno = n.end_lineno
                if n.end_col_offset:
                    end_col_offset = n.end_col_offset
            elif n.end_lineno == end_lineno and n.end_col_offset and (n.end_col_offset > end_col_offset):
                end_col_offset = n.end_col_offset
        return (lineno, col_offset, end_lineno, end_col_offset)

def unparse(cls, node: ast.AST, indent: int) -> str:
        """Unparse AST node to string.  Indent any lines that are not the first line."""
        lines = ast.unparse(node).splitlines(keepends=True)
        if len(lines) > 1:
            lines[1:] = [f"{' ' * indent}{line}" for line in lines[1:]]
        return ''.join(lines)
